#include <stdio.h>

int main() {
  int numbers[5] = {10, 20, 30, 40, 50};
  for (int i = 0; i < 5; i++) {
    printf("Element %d: %d\n", i, numbers[i]);
  }
  return 0;
}
// Output:
// Element 0: 10
// Element 1: 20
// Element 2: 30
// Element 3: 40
// Element 4: 50

#include <stdio.h>

int main() {
  int numbers[3] = {1, 2, 3};
  printf("Original: %d\n", numbers[1]);
  numbers[1] = 99;
  printf("Modified: %d\n", numbers[1]);
  return 0;
}
// Output:
// Original: 2
// Modified: 99

#include <stdio.h>

int main() {
  int matrix[2][3] = {
    {1, 2, 3},
    {4, 5, 6}
  };
  for (int i = 0; i < 2; i++) {
    for (int j = 0; j < 3; j++) {
      printf("Element [%d][%d]: %d\n", i, j, matrix[i][j]);
    }
  }
  return 0;
}
// Output:
// Element [0][0]: 1
// Element [0][1]: 2
// Element [0][2]: 3
// Element [1][0]: 4
// Element [1][1]: 5
// Element [1][2]: 6

#include <stdio.h>

int main() {
  int numbers[3] = {1, 2, 3};
  printf("Invalid access: %d\n", numbers[3]);
  return 0;
}
// Output: (Gözlənilməz nəticə, çünki numbers[3] mövcud deyil)

